      {"id":60,"question":"'Reading comprehension skill' for class 6-8 SCERT focuses on?","options":["Only grammar","Understanding, inference and critical thinking","Only vocabulary","Only writing"],"answer":1,"answer_text":"Understanding, inference and critical thinking"}
