// 1. Lesson Format (for mocktest/all/)
function makeLessonJSON(code, title, arr) {
  const sections = [
    {
      title: "தேர்வு விவரம்",
      content: `இந்த மாதிரித் தேர்வு 150 கேள்விகளைக் கொண்டது. ${code === 'mt_3_ms' ? 'உளவியல்-30, தமிழ்-30, ஆங்கிலம்-30, கணிதம்-30, அறிவியல்-30' : 'தமிழ்-30, ஆங்கிலம்-30, உளவியல்-30, சமூக அறிவியல்-60'}.`
    }
  ];

  // Group questions by section
  const groups = {};
  arr.forEach(q => {
    if (!groups[q.section]) groups[q.section] = [];
    groups[q.section].push(q);
  });

  Object.keys(groups).forEach(secName => {
    sections.push({
      title: `${secName} (${groups[secName].length} வினாக்கள்)`,
      content: groups[secName].map((q, idx) => ({
        text: `${groups[secName][0].id + idx}. ${q.question}\n**விடை:** ${q.options[q.answer]}`
      }))
    });
  });

  return JSON.stringify({
    code: code,
    title: title,
    sections: sections,
    quiz: {
      questions: arr
    }
  }, null, 2);
}

// 2. Exam Format (for model_test/3/)
function makeExamJSON(unitId, unitTitle, arr) {
  return JSON.stringify({
    unit: unitId,
    subject: "TET Model Test",
    class: "8",
    term: "Annual",
    title: unitTitle,
    summary: "அனைத்துப் பாடங்களையும் உள்ளடக்கிய 150 வினாக்கள் கொண்ட மாதிரித் தேர்வு.",
    sections: [],
    quiz: {
      questions: arr.map(q => ({
        question: q.question,
        options: q.options,
        answer: q.answer,
        explanation: q.ex
      }))
    }
  }, null, 2);
}

